#!/usr/bin/env node
/**
 * One-shot migration: products.json (191 entries, canonical) → lib/catalogue-data.ts.
 *
 * Run from the project root:
 *     node scripts/migrate-catalogue.mjs
 *
 * Output: lib/catalogue-data.ts overwritten with the full 191-product PRODUCTS array.
 *
 * Why this script lives in the repo: products.json may be regenerated by the
 * data team (re-export from WordPress, manual edits to specs, new products).
 * Re-running this script is the supported path to refresh the TypeScript fixture
 * — do NOT hand-edit lib/catalogue-data.ts after running it.
 *
 * Mapping rules are documented in CLAUDE_CODE_MIGRATION_PROMPT.md. This file
 * is the executable version of those rules — when in doubt, the prompt's rules
 * are the spec; this script is the implementation.
 */

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const PROJECT_ROOT = path.resolve(__dirname, "..");
const PRODUCTS_JSON = path.join(PROJECT_ROOT, "products.json");
const OUTPUT_PATH = path.join(PROJECT_ROOT, "lib", "catalogue-data.ts");

const VALID_CERTIFICATIONS = new Set([
  "WaterMark",
  "WELS",
  "NSF",
  "AS/NZS 4020",
  "AS/NZS 3497",
]);

// Human-readable names for each category slug — used to build the
// `categoryPath` breadcrumb on each Product record.
const CATEGORY_TITLES = {
  // Top-level
  "water-filters": "Water Filters",
  "drinking-bubblers": "Drinking Bubblers",
  "water-pumps": "Water Pumps",
  "chemical-dosing-tanks": "Chemical Dosing Tanks",
  bathroom: "Bathroom & Kitchen",

  // water-filters/
  "whole-house-filters": "Whole House Filters",
  "under-sink-ro-systems": "Under Sink & RO Systems",
  "uv-sterilisers": "UV Sterilisers",
  "shower-filters": "Shower Filters",
  "replacement-cartridges": "Replacement Cartridges",
  "filter-taps": "Filter Taps",
  "filter-fittings": "Filter Fittings",

  // drinking-bubblers/
  "commercial-bubblers": "Commercial Bubblers",
  "water-coolers": "Water Coolers",
  "bubbler-parts": "Bubbler Parts",

  // water-pumps/
  "12v-caravan-pumps": "12V Caravan Pumps",
  "booster-pumps": "Booster Pumps",
  "pressure-tanks": "Pressure Tanks",

  // bathroom/
  toilets: "Toilets",
  "bathroom-taps": "Bathroom Taps",
  "kitchen-taps": "Kitchen Taps",
  "vanities-and-basins": "Vanities & Basins",
  "showers-and-fixtures": "Showers & Fixtures",
  "bathroom-accessories": "Bathroom Accessories",
};

// SKU prefix per top-level — produces SKUs like EA-WF-4135.
// Note: deriving from main_collection means the renamed `commercial-bubblers`
// → `drinking-bubblers` migration changes the bubbler SKUs from EA-CB-* (old
// fixture) to EA-DB-* (this catalogue). All 191 products in products.json
// have sku=null, so this is a clean re-keying — no preserved SKUs to honour.
const SKU_PREFIX = {
  "water-filters": "EA-WF",
  "drinking-bubblers": "EA-DB",
  "water-pumps": "EA-WP",
  "chemical-dosing-tanks": "EA-CT",
  bathroom: "EA-BA",
};

function deriveSku(mainCollection, wpId) {
  const prefix = SKU_PREFIX[mainCollection] ?? "EA-XX";
  return `${prefix}-${wpId}`;
}

function priceBand(price) {
  if (price < 30) return "Under $30";
  if (price < 100) return "$30 – $100";
  if (price < 300) return "$100 – $300";
  if (price < 1000) return "$300 – $1,000";
  return "$1,000+";
}

function parseStages(raw) {
  if (raw == null) return undefined;
  const m = String(raw).match(/(\d+)/);
  return m ? Number(m[1]) : undefined;
}

function parseTechnology(raw) {
  if (!raw) return undefined;
  // filter_media may be comma- or +-separated. Trim whitespace, drop empties.
  const parts = String(raw)
    .split(/[,+]/)
    .map((s) => s.trim())
    .filter(Boolean);
  return parts.length > 0 ? parts : undefined;
}

function parseRemoves(raw) {
  if (!raw) return undefined;
  const parts = String(raw)
    .split(/,/)
    .map((s) => s.trim().toLowerCase())
    .filter(Boolean);
  return parts.length > 0 ? parts : undefined;
}

function parseCertifications(raw) {
  if (!raw) return [];
  return String(raw)
    .split(",")
    .map((s) => s.trim())
    .filter((s) => VALID_CERTIFICATIONS.has(s));
}

function parseFlowRate(raw) {
  if (raw == null) return undefined;
  // max_flow_lph values may be numeric or strings like "1500" or "1500 L/h".
  const m = String(raw).match(/(\d+(?:\.\d+)?)/);
  return m ? `${m[1]} LPH` : undefined;
}

function deriveApplication(productType, title) {
  const apps = [];
  if (productType === "bubbler" || productType === "water_cooler") {
    apps.push("commercial");
  }
  const lower = title.toLowerCase();
  if (lower.includes("bench top") || lower.includes("rental")) {
    apps.push("rental friendly");
  }
  return apps.length > 0 ? apps : undefined;
}

function deriveFacets(p, price) {
  const spec = p.specifications ?? {};
  const facets = {};

  const stages = parseStages(spec.filtration_stages);
  if (stages !== undefined) facets.stages = stages;

  if (spec.housing_size) facets.housing_size = String(spec.housing_size);
  if (spec.micron_rating) facets.micron = String(spec.micron_rating);

  const flow = parseFlowRate(spec.max_flow_lph);
  if (flow) facets.flow_rate = flow;

  const tech = parseTechnology(spec.filter_media);
  if (tech) facets.technology = tech;

  const removes = parseRemoves(spec.reduces);
  if (removes) facets.removes = removes;

  const application = deriveApplication(p.product_type, p.title);
  if (application) facets.application = application;

  // price_band is omitted for products without a real price — the band would
  // misleadingly read "Under $30" for a $0 placeholder.
  if (price > 0) facets.price_band = priceBand(price);

  return facets;
}

function deriveCategoryPath(mainCollection, subCollection) {
  const main = CATEGORY_TITLES[mainCollection] ?? mainCollection;
  if (!subCollection) return [main];
  const sub = CATEGORY_TITLES[subCollection] ?? subCollection;
  return [main, sub];
}

/**
 * Truncate to 200 chars at a word boundary, appending an ellipsis only when
 * the source string was actually trimmed. The catalogue's short_description
 * field averages ~250 chars; mid-word cuts look broken in card UI.
 */
function truncateShort(text) {
  if (!text) return "";
  if (text.length <= 200) return text;
  const slice = text.slice(0, 200);
  const lastSpace = slice.lastIndexOf(" ");
  const cut = lastSpace > 150 ? slice.slice(0, lastSpace) : slice;
  return `${cut.trimEnd()}…`;
}

function dedupe(arr) {
  return Array.from(new Set(arr));
}

function mapProduct(p) {
  // Resolve sub-category: prefer explicit sub_collection, else first non-main
  // collection, else fall back to main_collection (single-product flat cats).
  const subCategory =
    p.sub_collection ||
    (p.collections ?? []).find((c) => c !== p.main_collection) ||
    p.main_collection;

  const regularPrice = (p.price && p.price.regular) || 0;
  const salePrice = (p.price && p.price.sale) || null;
  const onSale = salePrice != null && salePrice < regularPrice;
  const displayPrice = onSale ? salePrice : regularPrice;

  // Stock: out_of_stock if Shopify says so OR if there's no real price (the
  // PDP buy box shows "Out of stock — call for ETA" which is the right UX
  // for unpriced products).
  const stockStatus = !p.in_stock || regularPrice <= 0 ? "out_of_stock" : "in_stock";

  return {
    id: String(p.old_wp_id),
    sku: p.sku || deriveSku(p.main_collection, p.old_wp_id),
    slug: p.handle,
    title: p.title,
    primaryCategory: p.main_collection,
    subCategory,
    categoryPath: deriveCategoryPath(p.main_collection, subCategory),
    price: displayPrice,
    regularPrice,
    onSale,
    stockStatus,
    shortDescription: truncateShort(p.short_description ?? ""),
    longDescription: p.description ?? "",
    facets: deriveFacets(p, displayPrice),
    images: p.images ?? [],
    tags: dedupe(p.tags ?? []),
    certifications: parseCertifications(
      (p.specifications ?? {}).certifications
    ),
    kitHint: null,
    seoTitle: p.meta_title ?? p.title,
    seoDescription: p.meta_description ?? p.short_description ?? "",
  };
}

// --- TypeScript emission ----------------------------------------------------

/**
 * Emit a JS value as TypeScript-friendly source, double-quoted strings with
 * standard escapes and `\u00XX` for the few non-ASCII chars that the JSON
 * loader didn't already smooth over. Long descriptions go through a separate
 * template-literal path so authors can read the markdown unwrapped.
 */
function emitString(s) {
  return JSON.stringify(s);
}

function emitTemplate(s) {
  // Backticks need escaping; ${ does too (would interpolate).
  const escaped = s.replace(/\\/g, "\\\\").replace(/`/g, "\\`").replace(/\$\{/g, "\\${");
  return "`" + escaped + "`";
}

function emitFacets(facets) {
  const keys = Object.keys(facets);
  if (keys.length === 0) return "{}";
  const lines = keys.map((k) => {
    const v = facets[k];
    if (typeof v === "string") return `      ${JSON.stringify(k)}: ${emitString(v)},`;
    if (typeof v === "number") return `      ${JSON.stringify(k)}: ${v},`;
    if (Array.isArray(v))
      return `      ${JSON.stringify(k)}: [${v.map(emitString).join(", ")}],`;
    return `      ${JSON.stringify(k)}: ${JSON.stringify(v)},`;
  });
  return `{\n${lines.join("\n")}\n    }`;
}

function emitArray(arr, indent = "      ") {
  if (arr.length === 0) return "[]";
  const lines = arr.map((s) => `${indent}${emitString(s)},`);
  return `[\n${lines.join("\n")}\n    ]`;
}

function emitProduct(p) {
  return `  {
    id: ${emitString(p.id)},
    sku: ${emitString(p.sku)},
    slug: ${emitString(p.slug)},
    title: ${emitString(p.title)},
    primaryCategory: ${emitString(p.primaryCategory)},
    subCategory: ${emitString(p.subCategory)},
    categoryPath: [${p.categoryPath.map(emitString).join(", ")}],
    price: ${p.price},
    regularPrice: ${p.regularPrice},
    onSale: ${p.onSale},
    stockStatus: ${emitString(p.stockStatus)},
    shortDescription: ${emitString(p.shortDescription)},
    longDescription: ${emitTemplate(p.longDescription)},
    facets: ${emitFacets(p.facets)},
    images: ${emitArray(p.images)},
    tags: ${emitArray(p.tags)},
    certifications: [${p.certifications.map(emitString).join(", ")}],
    kitHint: ${p.kitHint == null ? "null" : emitString(p.kitHint)},
    seoTitle: ${emitString(p.seoTitle)},
    seoDescription: ${emitString(p.seoDescription)},
  },`;
}

function main() {
  const raw = fs.readFileSync(PRODUCTS_JSON, "utf8");
  const data = JSON.parse(raw);
  const products = data.products;

  if (!Array.isArray(products)) {
    throw new Error("products.json: expected an array under `products`");
  }

  const mapped = products.map(mapProduct);

  // Sanity reports — printed to stdout so they show up in CI logs and in the
  // terminal when re-running locally.
  const noPrice = mapped.filter((p) => p.regularPrice <= 0);
  const noCerts = mapped.filter((p) => p.certifications.length === 0);
  const handFinishedCount = products.filter(
    (p) => p.migration_notes && p.migration_notes.hand_finished
  ).length;
  const skuClashes = new Map();
  for (const p of mapped) {
    skuClashes.set(p.sku, (skuClashes.get(p.sku) ?? 0) + 1);
  }
  const dupeSkus = [...skuClashes.entries()].filter(([, n]) => n > 1);
  if (dupeSkus.length > 0) {
    throw new Error(
      `Duplicate SKUs after derivation — investigate before importing:\n` +
        dupeSkus.map(([sku, n]) => `  ${sku}: ${n}×`).join("\n")
    );
  }

  const slugClashes = new Map();
  for (const p of mapped) {
    slugClashes.set(p.slug, (slugClashes.get(p.slug) ?? 0) + 1);
  }
  const dupeSlugs = [...slugClashes.entries()].filter(([, n]) => n > 1);
  if (dupeSlugs.length > 0) {
    throw new Error(
      `Duplicate slugs (handles) after migration — Shopify will reject the import:\n` +
        dupeSlugs.map(([slug, n]) => `  ${slug}: ${n}×`).join("\n")
    );
  }

  const header = `/**
 * Product catalogue fixture — generated from products.json by
 * scripts/migrate-catalogue.mjs.
 *
 * DO NOT HAND-EDIT THIS FILE. Re-run the migration script:
 *     node scripts/migrate-catalogue.mjs
 *
 * Editorial content (titles, copy, images, facets, SEO) is the source of
 * truth here. Live price and stock are merged in at render time by
 * lib/shopify/product-state.ts — this fixture is the fallback when
 * Shopify is unavailable.
 *
 * Generated: ${new Date().toISOString()}
 * Products:  ${mapped.length}
 */

import type { Product } from "@/types/product";

export const PRODUCTS: Product[] = [
${mapped.map(emitProduct).join("\n")}
];
`;

  fs.writeFileSync(OUTPUT_PATH, header, "utf8");

  console.log(`Wrote ${OUTPUT_PATH}`);
  console.log(`  Products:        ${mapped.length}`);
  console.log(`  Hand-finished:   ${handFinishedCount}`);
  console.log(`  Missing price:   ${noPrice.length}  (marked out_of_stock)`);
  console.log(`  Missing certs:   ${noCerts.length}`);

  // Summary by main category for the PR description.
  const byPrimary = mapped.reduce((acc, p) => {
    acc[p.primaryCategory] = (acc[p.primaryCategory] ?? 0) + 1;
    return acc;
  }, {});
  console.log("\nProducts by primary category:");
  for (const [cat, n] of Object.entries(byPrimary).sort()) {
    console.log(`  ${cat}: ${n}`);
  }
}

main();
